INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (1013, 186351, 6, 1095, '�t☆幸福天使 爱情之翼^*^', '今夜，躺在床上翻来覆去总是睡不着，面对着眼前的这台电脑，看着窗外那闪烁星星，动起了手中的键盘，打开在咖啡里以往所写的一切，脑中细细地回忆、贪恋着，你与我相处的这些日子，我们在不知不觉中已经悄然走过了一段时间，我喜欢我们这样方式的相处与交流，让我感觉很陶醉。虽然有时是喜忧掺拌；有时你顶我、我顶你的，有时你迁就我、我让着你，但是我很快乐、开心，跟我以前谈感情的是不一样的，那种感觉是截然不同，我们从相识、相遇、相知、恋爱；这一路走来的日子虽然很短暂；彼此了解的还不够彻底，但是我知道在未来的时间里，你会陪我一起走下去、一起去面对，一起去了解的，不想让那幸福只停留在我们身边只那一瞬间，不是嘛？我也清楚地知道到，现在的男生都很喜欢自己的另一半是温柔、会撒娇，我直爽与活泼让我很少去那样子做，我也意识到自己的不足之处到底是在哪里，我也一直记着、清楚地知道，你喜欢的女孩子是什么样子，即使不可能做到你心目中想象的那么好，但我会努力去做得到最好、扮演好我的“角色”！
<br>而在一个月前的那一夜，你在电话那头对我所说的那一番话，当时虽然听了心很痛、很乱……，但是我把它收藏在心里，对于你来说可能不是什么值得再提起的事情，但对于我而言那是我们感情中的一个小插曲，假如没有那一晚的对话、那一个些的细节，现在的我们能走在一起吗？我也想让你了解我不喜欢，人家的背叛、别人的圆滑、自己的嘲笑；更不喜欢自己喜欢的人，对于自己的欺骗与不真诚，不想这样的事情在自己身上一点一点的升华，那是一件多么悲哀的事情！
<br>华丽的外表对于我们来说是多余的，但是难得的是我们的性格与爱好是那么的“臭气”相投，那是在茫茫人海中很难以遇见的。所以我是那么珍惜、小心翼翼地对待。当我们是属于不同的“圆”时，被拉到了一起那是一种很难得的缘分。多愁善感的我遇到你，是另外一个新的开始；我感觉我守护的“天使”已经回到了我的身边，在保护着我、保护着你。我知道，每次在我最失落、最无奈的时候；都是你在我身边支持着我、鼓励着我，我也知道，你的体贴、你的关心、你的呵护、无不让我感动、高兴。我们的感情看起来极为普通，但是回味起来时却是非常甜蜜的，身边的好朋友们也总是在我耳边说你的好、你的优点，要我认真的去面对、重视我们这份感情，你所做的一切我都看在眼里、甜在心里，而你总是那么的忍让着我、宠我……，让我有时得寸进尺、有时满怀信心地走下去，我很谢谢你！
<br>虽然这些天我们彼此有时斗嘴闹得不是很开心，但是我们都体谅与谦让着对方，让我们之间走得更近、拉得更近了，而那个“念头”希望它从你的内心里彻底的消失吧！我们彼此好好的维护这段感情、好好的去经营着它，不是么？我希望你也是好好的工作照顾、好自己的身体！我希望我全心全意的付出 能唤回爱神对我多一点的关心多一点的眷顾。幸福的生活就像天上变幻着的云彩一样，永远不会是一个样儿！
<br>在爱的国界里，不要让爱搁浅只要付出过没有什么会值得后悔的，只要自己努力过自己才不会去懊恼！身边的人与事每天都在日以继夜地努力着、拼命着；每个人都想要一段唯美、浪漫的爱情，但是他（她）们如果能遇到一个自己喜欢的、性格相符的人，那是一件多么好的事情！希望你们都找到一个自己真爱的他（她）！就趁它尚未凋谢之前好好呼吸它那甜蜜的气息，好好感受那温柔的缠绵吧!希望你们好运!
<br>“双手插口袋，帽子带歪歪，只有……  了解你！”世界那么大，我却是
<br>
<br>你手心里唯一的宝贝 	⌒ō⌒
<br>
<br>灿烂的向日葵花朵儿，像那朵朵菊花在阳光下斗艳！
